starter:
h1 { font-size: clamp(2rem, 6vw, 4rem); }
h2 { font-size: clamp(1.6rem, 5vw, 3.2rem); }
h3 { font-size: clamp(1.3rem, 4vw, 2.6rem); }

.container {
  width: min(calc(100% - 2rem), 1200px);
  margin: 0 auto;
}
.container-sm {
  width: min(calc(100% - 2rem), 800px);
}

.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(clamp(200px, 30vw, 350px), 1fr));
  gap: clamp(0.5rem, 2vw, 2rem);
}
.card {
  padding: clamp(1rem, 3vw, 2rem);
}

:root {
  --space-xs: clamp(0.125rem, 0.5vw, 0.25rem);
  --space-sm: clamp(0.25rem, 1vw, 0.5rem);
  --space-md: clamp(0.5rem, 2vw, 1rem);
  --space-lg: clamp(1rem, 4vw, 2rem);
  --radius: clamp(4px, 1vw, 12px);
  --font-sm: clamp(0.75rem, 1.5vw, 0.875rem);
  --font-md: clamp(0.875rem, 2vw, 1rem);
}
